VALUES
  ('social-worker-moex-05770', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會團體工作的三個模型中，社會目標模型之目的及目標在於：', '["針對行為失功能的團體成員", "在團體成員間形成一個互助體系", "達到最佳的適應和社會化", "社會意識、社會責任等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05771', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會交換理論（social exchange theory）是將焦點著重在個別成員的行為上，Blau（1964）、Homans（1961）、 Thibaut和Kelly（1959）等學者是採此種取向原則來發展團體。下列何者是其理論觀點？', '["當人們在團體互動時，每一個成員都會試圖表現出以能趨吉避凶的行為為唯一目標", "團體成員彼此開始互動，是因為在社會交換的過程中會提供某些價值觀", "當人們在團體互動時，可能僅有極少部分成員會試圖表現出能獲得最高酬賞與最低懲罰的行為", "當人們在團體互動時，每一個成員都會試圖表現出能以獲得最高酬賞的行為為唯一目標"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05772', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社會團體工作中，團體領導者的權力基礎中其所謂之「連結的權力」，下列何者正確？', '["動員有影響力的人或資源", "具備知識與技巧", "深受喜愛和欽佩", "提供社會性或實質具體之獎賞"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05773', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '進行社會團體工作時，在團體發展的中間階段，工作者可以進行不同的活動以使團體工作具結構化，下 列何種活動錯誤？', '["讓成員知道團體開始及結束會準時", "在聚會結束時會做摘要和結論", "發展並促使團體溝通與互動模式有更多元之變化與創意", "聚焦在多元層次的介入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05774', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者運用生態系統觀點處遇個案時，在處遇過程中，運用正式與非正式資源以達成處遇目標，是 那個系統的概念？', '["機構系統", "標的系統", "行動系統", "案主系統"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05775', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「就在我說話的時刻，我注意到你的眼神並沒有注視我，你好像在看遠方而且在想什麼事情似的，你現 在到底在想些什麼？」下列何者正確？', '["是使用勸告模式", "是使用立即性反應", "是使用面質型式", "是集中焦點模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05776', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '身為一個社會工作師，有義務對整個實務運作的每一步驟做好紀錄，近來可嘗試「目標焦點」 （goal-focused）的實驗性格式，簡稱GAAP，下列敘述何者錯誤？', '["G（Goals）：目標", "A（Activities）：活動", "A（Action）：行動", "P（Plans）：計畫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05777', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '如果比較社區層次的介入與以社區為基礎的介入，下列敘述何者正確？', '["以社區為基礎的介入目的是在於改變社區的態度或行為，充權是重要的哲學基礎", "社區層次的介入決策在於「由下而上」，充權是重要的哲學基礎", "以社區為基礎的介入係主要仍是「由上而下」進行決策，充權是重要的哲學基礎", "社區層次的介入是藉由個人與家庭的變遷作為結果測量，優勢是重要的哲學基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05778', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Kretzmann and McKnight（1993）曾指出，若過度從問題面相來看待社區，下列議題何者正確？', '["社區將僅依賴內部自主改變的力量，甚至無法掌握社區外部資源的內涵", "只會運用社區外的資源或是專業人員協助社區解決問題", "社區工作者必須了解到「政府干預的力量」", "部分社會工作者雖然注意到社會制度、組織或是服務體系，但也太過重視人們日常生活息息相關的環境"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05779', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '所謂「社區資產」的類型，下列何者錯誤？', '["有形資本（physical capital）", "人力資本（human capital）", "社會資本（social capital）", "土地資本（land capital）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
